// Cloudflare Worker: API Integration with SendGrid and Stripe
// wrangler.toml configuration expected:
// [vars]
// ALLOWED_ORIGINS = "https://yourdomain.com"
// 
// [secrets]
// SENDGRID_API_KEY
// STRIPE_SECRET_KEY
// API_AUTH_TOKEN

const CORS_HEADERS = {
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type, Authorization',
  'Access-Control-Max-Age': '86400',
};

function getCorsHeaders(request, env) {
  const origin = request.headers.get('Origin') || '';
  const allowedOrigins = (env.ALLOWED_ORIGINS || '').split(',').map(o => o.trim());
  const headers = { ...CORS_HEADERS };

  if (allowedOrigins.includes(origin) || allowedOrigins.includes('*')) {
    headers['Access-Control-Allow-Origin'] = origin;
  }

  return headers;
}

class AppError extends Error {
  constructor(message, statusCode = 500, code = 'INTERNAL_ERROR') {
    super(message);
    this.statusCode = statusCode;
    this.code = code;
  }
}

function jsonResponse(data, status = 200, extraHeaders = {}) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
      ...extraHeaders,
    },
  });
}

function errorResponse(error, extraHeaders = {}) {
  const statusCode = error.statusCode || 500;
  const code = error.code || 'INTERNAL_ERROR';
  const message = statusCode === 500 ? 'Internal server error' : error.message;

  console.error(`[ERROR] ${code}: ${error.message}`, error.stack);

  return jsonResponse(
    {
      success: false,
      error: {
        code,
        message,
      },
    },
    statusCode,
    extraHeaders
  );
}

function authenticate(request, env) {
  const authHeader = request.headers.get('Authorization');

  if (!authHeader) {
    throw new AppError('Missing Authorization header', 401, 'UNAUTHORIZED');
  }

  const [scheme, token] = authHeader.split(' ');

  if (scheme !== 'Bearer' || !token) {
    throw new AppError('Invalid Authorization format. Use: Bearer <token>', 401, 'UNAUTHORIZED');
  }

  if (token !== env.API_AUTH_TOKEN) {
    throw new AppError('Invalid API token', 403, 'FORBIDDEN');
  }

  return true;
}

function validateEmailPayload(body) {
  const errors = [];

  if (!body.to || typeof body.to !== 'string' || !body.to.includes('@')) {
    errors.push('Valid "to" email address is required');
  }

  if (!body.subject || typeof body.subject !== 'string' || body.subject.trim().length === 0) {
    errors.push('"subject" is required');
  }

  if (!body.content && !body.html) {
    errors.push('Either "content" (plain text) or "html" is required');
  }

  if (!body.from || typeof body.from !== 'string' || !body.from.includes('@')) {
    errors.push('Valid "from" email address is required');
  }

  if (errors.length > 0) {
    throw new AppError(`Validation failed: ${errors.join('; ')}`, 400, 'VALIDATION_ERROR');
  }
}

function validatePaymentPayload(body) {
  const errors = [];

  if (!body.amount || typeof body.amount !== 'number' || body.amount < 50) {
    errors.push('"amount" must be a number >= 50 (in cents)');
  }

  if (!body.currency || typeof body.currency !== 'string') {
    errors.push('"currency" is required (e.g., "usd")');
  }

  const validCurrencies = ['usd', 'eur', 'gbp', 'cad', 'aud', 'jpy'];
  if (body.currency && !validCurrencies.includes(body.currency.toLowerCase())) {
    errors.push(`"currency" must be one of: ${validCurrencies.join(', ')}`);
  }

  if (errors.length > 0) {
    throw new AppError(`Validation failed: ${errors.join('; ')}`, 400, 'VALIDATION_ERROR');
  }
}

function validateRefundPayload(body) {
  if (!body.payment_intent_id || typeof body.payment_intent_id !== 'string') {
    throw new AppError('"payment_intent_id" is required', 400, 'VALIDATION_ERROR');
  }

  if (body.amount !== undefined && (typeof body.amount !== 'number' || body.amount < 1)) {
    throw new AppError('"amount" must be a positive number (in cents) if provided', 400, 'VALIDATION_ERROR');
  }
}

async function retryFetch(url, options, maxRetries = 3, baseDelay = 1000) {
  let lastError;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      const response = await fetch(url, options);

      if (response.status === 429) {
        const retryAfter = response.headers.get('Retry-After');
        const delay = retryAfter ? parseInt(retryAfter) * 1000 : baseDelay * Math.pow(2, attempt);

        if (attempt < maxRetries) {
          await new Promise(resolve => setTimeout(resolve, delay));
          continue;
        }
      }

      if (response.status >= 500 && attempt < maxRetries) {
        await new Promise(resolve => setTimeout(resolve, baseDelay * Math.pow(2, attempt)));
        continue;
      }

      return response;
    } catch (error) {
      lastError = error;
      if (attempt < maxRetries) {
        await new Promise(resolve => setTimeout(resolve, baseDelay * Math.pow(2, attempt)));
        continue;
      }
    }
  }

  throw new AppError(
    `Failed after ${maxRetries + 1} attempts: ${lastError?.message || 'Unknown error'}`,
    502,
    'UPSTREAM_ERROR'
  );
}

// =====================
// SendGrid Email Service
// =====================

async function sendEmail(body, env) {
  validateEmailPayload(body);

  const sendgridPayload = {
    personalizations: [
      {
        to: [{ email: body.to, name: body.to_name || undefined }],
        ...(body.cc ? { cc: [{ email: body.cc }] } : {}),
        ...(body.bcc ? { bcc: [{ email: body.bcc }] } : {}),
      },
    ],
    from: {
      email: body.from,
      name: body.from_name || undefined,
    },
    subject: body.subject,
    content: [],
  };

  if (body.content) {
    sendgridPayload.content.push({
      type: 'text/plain',
      value: body.content,
    });
  }

  if (body.html) {
    sendgridPayload.content.push({
      type: 'text/html',
      value: body.html,
    });
  }

  if (body.reply_to) {
    sendgridPayload.reply_to = { email: body.reply_to };
  }

  if (body.categories && Array.isArray(body.categories)) {
    sendgridPayload.categories = body.categories;
  }

  const response = await retryFetch('https://api.sendgrid.com/v3/mail/send', {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${env.SENDGRID_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(sendgridPayload),
  });

  if (response.status === 202 || response.status === 200) {
    const messageId = response.headers.get('X-Message-Id');
    return {
      success: true,
      message: 'Email sent successfully',
      message_id: messageId || null,
    };
  }

  let errorBody;
  try {
    errorBody = await response.json();
  } catch {
    errorBody = await response.text();
  }

  console.error('[SendGrid Error]', JSON.stringify(errorBody));

  if (response.status === 401) {
    throw new AppError('SendGrid authentication failed', 502, 'SENDGRID_AUTH_ERROR');
  }

  if (response.status === 400) {
    const message = errorBody?.errors?.[0]?.message || 'Invalid email request';
    throw new AppError(`SendGrid: ${message}`, 400, 'SENDGRID_VALIDATION_ERROR');
  }

  throw new AppError(
    `SendGrid API error (${response.status})`,
    502,
    'SENDGRID_ERROR'
  );
}

// =====================
// Stripe Payment Service
// =====================

async function stripeRequest(endpoint, method, params, env) {
  const url = `https://api.stripe.com/v1${endpoint}`;

  const options = {
    method,
    headers: {
      Authorization: `Basic ${btoa(env.STRIPE_SECRET_KEY + ':')}`,
      'Content-Type': 'application/x-www-form-urlencoded',
      'Stripe-Version': '2023-10-16',
    },
  };

  if (params && (method === 'POST' || method === 'PUT')) {
    const formBody = new URLSearchParams();
    flattenParams(params, formBody, '');
    options.body = formBody.toString();
  }

  const response = await retryFetch(url, options);

  const responseBody = await response.json();

  if (!response.ok) {
    console.error('[Stripe Error]', JSON.stringify(responseBody));

    const stripeError = responseBody.error;

    if (response.status === 401) {
      throw new AppError('Stripe authentication failed', 502, 'STRIPE_AUTH_ERROR');
    }

    if (stripeError) {
      const message = stripeError.message || 'Stripe request failed';
      const code = stripeError.code || 'STRIPE_ERROR';

      if (stripeError.type === 'card_error') {
        throw new AppError(message, 400, `STRIPE_CARD_ERROR_${code.toUpperCase()}`);
      }

      if (stripeError.type === 'invalid_request_error') {
        throw new AppError(message, 400, 'STRIPE_INVALID_REQUEST');
      }

      throw new AppError(message, 502, 'STRIPE_ERROR');
    }

    throw new AppError(`Stripe API error (${response.status})`, 502, 'STRIPE_ERROR');
  }

  return responseBody;
}

function flattenParams(obj, formBody, prefix) {
  for (const [key, value] of Object.entries(obj)) {
    const fullKey = prefix ? `${prefix}[${key}]` : key;

    if (value !== null && value !== undefined && typeof value === 'object' && !Array.isArray(value)) {
      flattenParams(value, formBody, fullKey);
    } else if (Array.isArray(value)) {
      value.forEach((item, index) => {
        if (typeof item === 'object') {
          flattenParams(item, formBody, `${fullKey}[${index}]`);
        } else {
          formBody.append(`${fullKey}[${index}]`, item);
        }
      });
    } else if (value !== null && value !== undefined) {
      formBody.append(fullKey, value);
    }
  }
}

async function createPaymentIntent(body, env) {
  validatePaymentPayload(body);

  const params = {
    amount: Math.round(body.amount),
    currency: body.currency.toLowerCase(),
    automatic_payment_methods: { enabled: 'true' },
  };

  if (body.description) {
    params.description = body.description;
  }

  if (body.customer_email) {
    params.receipt_email = body.customer_email;
  }

  if (body.metadata && typeof body.metadata === 'object') {
    params.metadata = body.metadata;
  }

  if (body.customer_id) {
    params.customer = body.customer_id;
  }

  const paymentIntent = await stripeRequest('/payment_intents', 'POST', params, env);

  return {
    success: true,
    payment_intent: {
      id: paymentIntent.id,
      client_secret: paymentIntent.client_secret,
      amount: paymentIntent.amount,
      currency: paymentIntent.currency,
      status: paymentIntent.status,
    },
  };
}

async function retrievePaymentIntent(paymentIntentId, env) {
  if (!paymentIntentId || !paymentIntentId.startsWith('pi_')) {
    throw new AppError('Valid payment_intent_id starting with "pi_" is required', 400, 'VALIDATION_ERROR');
  }

  const paymentIntent = await stripeRequest(`/payment_intents/${paymentIntentId}`, 'GET', null, env);

  return {
    success: true,
    payment_intent: {
      id: paymentIntent.id,
      amount: paymentIntent.amount,
      currency: paymentIntent.currency,
      status: paymentIntent.status,
      created: paymentIntent.created,
      metadata: paymentIntent.metadata,
    },
  };
}

async function createRefund(body, env) {
  validateRefundPayload(body);

  const params = {
    payment_intent: body.payment_intent_id,
  };

  if (body.amount) {
    params.amount = Math.round(body.amount);
  }

  if (body.reason) {
    const validReasons = ['duplicate', 'fraudulent', 'requested_by_customer'];
    if (validReasons.includes(body.reason)) {
      params.reason = body.reason;
    }
  }

  const refund = await stripeRequest('/refunds', 'POST', params, env);

  return {
    success: true,
    refund: {
      id: refund.id,
      amount: refund.amount,
      currency: refund.currency,
      status: refund.status,
      payment_intent: refund.payment_intent,
    },
  };
}

async function createCustomer(body, env) {
  if (!body.email || !body.email.includes('@')) {
    throw new AppError('Valid "email" is required', 400, 'VALIDATION_ERROR');
  }

  const params = {
    email: body.email,
  };

  if (body.name) params.name = body.name;
  if (body.phone) params.phone = body.phone;
  if (body.metadata) params.metadata = body.metadata;

  const customer = await stripeRequest('/customers', 'POST', params, env);

  return {
    success: true,
    customer: {
      id: customer.id,
      email: customer.email,
      name: customer.name,
      created: customer.created,
    },
  };
}

// =====================
// Webhook handler (Stripe)
// =====================

async function handleStripeWebhook(request, env) {
  const signature = request.headers.get('stripe-signature');

  if (!signature) {
    throw new AppError('Missing Stripe signature', 400, 'WEBHOOK_ERROR');
  }

  const rawBody = await request.text();

  // Verify webhook signature
  if (env.STRIPE_WEBHOOK_SECRET) {
    const isValid = await verifyStripeSignature(rawBody, signature, env.STRIPE_WEBHOOK_SECRET);
    if (!isValid) {
      throw new AppError('Invalid Stripe webhook signature', 400, 'WEBHOOK_SIGNATURE_ERROR');
    }
  }

  const event = JSON.parse(rawBody);

  console.log(`[Stripe Webhook] Received event: ${event.type}, id: ${event.id}`);

  switch (event.type) {
    case 'payment_intent.succeeded': {
      const paymentIntent = event.data.object;
      console.log(`[Stripe Webhook] Payment succeeded: ${paymentIntent.id}, amount: ${paymentIntent.amount}`);
      // Add your business logic here (e.g., fulfill order, update database)
      break;
    }

    case 'payment_intent.payment_failed': {
      const paymentIntent = event.data.object;
      const error = paymentIntent.last_payment_error;
      console.log(
        `[Stripe Webhook] Payment failed: ${paymentIntent.id}, reason: ${error?.message || 'unknown'}`
      );
      // Add your business logic here (e.g., notify customer)
      break;
    }

    case 'charge.refunded': {
      const charge = event.data.object;
      console.log(`[Stripe Webhook] Charge refunded: ${charge.id}`);
      break;
    }

    case 'customer.created': {
      const customer = event.data.object;
      console.log(`[Stripe Webhook] Customer created: ${customer.id}`);
      break;
    }

    default:
      console.log(`[Stripe Webhook] Unhandled event type: ${event.type}`);
  }

  return { success: true, received: true, event_type: event.type };
}

async function verifyStripeSignature(payload, sigHeader, secret) {
  try {
    const pairs = sigHeader.split(',').reduce((acc, item) => {
      const [key, value] = item.split('=');
      acc[key.trim()] = value.trim();
      return acc;
    }, {});

    const timestamp = pairs['t'];
    const signature = pairs['v1'];

    if (!timestamp || !signature) return false;

    // Check timestamp tolerance (5 minutes)
    const tolerance = 300;
    const now = Math.floor(Date.now() / 1000);
    if (Math.abs(now - parseInt(timestamp)) > tolerance) return false;

    const signedPayload = `${timestamp}.${payload}`;
    const encoder = new TextEncoder();

    const key = await crypto.subtle.importKey(
      'raw',
      encoder.encode(secret),
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['sign']
    );

    const signatureBuffer = await crypto.subtle.sign('HMAC', key, encoder.encode(signedPayload));
    const expectedSignature = Array.from(new Uint8Array(signatureBuffer))
      .map(b => b.toString(16).padStart(2, '0'))
      .join('');

    return expectedSignature === signature;
  } catch (error) {
    console.error('[Webhook Signature Verification Error]', error.message);
    return false;
  }
}

// =====================
// Rate Limiting (simple in-memory per-isolate)
// =====================

const rateLimitMap = new Map();
const RATE_LIMIT_WINDOW = 60000; // 1 minute
const RATE_LIMIT_MAX = 60; // requests per window

function checkRateLimit(clientIP) {
  const now = Date.now();
  const key = clientIP || 'unknown';

  const entry = rateLimitMap.get(key);

  if (!entry || now - entry.windowStart > RATE_LIMIT_WINDOW) {
    rateLimitMap.set(key, { windowStart: now, count: 1 });
    return true;
  }

  entry.count++;

  if (entry.count > RATE_LIMIT_MAX) {
    throw new AppError('Rate limit exceeded. Please try again later.', 429, 'RATE_LIMIT_EXCEEDED');
  }

  return true;
}

// Clean up stale entries periodically
function cleanupRateLimits() {
  const now = Date.now();
  for (const [key, entry] of rateLimitMap.entries()) {
    if (now - entry.windowStart > RATE_LIMIT_WINDOW * 2) {
      rateLimitMap.delete(key);
    }
  }
}

// =====================
// Router
// =====================

async function handleRequest(request, env, ctx) {
  const url = new URL(request.url);
  const path = url.pathname;
  const method = request.method;

  const corsHeaders = getCorsHeaders(request, env);

  // Handle CORS preflight
  if (method === 'OPTIONS') {
    return new Response(null, { status: 204, headers: corsHeaders });
  }

  try {
    const clientIP = request.headers.get('CF-Connecting-IP');
    checkRateLimit(clientIP);

    // Periodic cleanup (non-blocking)
    ctx.waitUntil(Promise.resolve().then(cleanupRateLimits));

    // Health check endpoint (no auth)
    if (path === '/health' && method === 'GET') {
      return jsonResponse(
        {
          success: true,
          status: 'healthy',
          timestamp: new Date().toISOString(),
          version: '1.0.0',
        },
        200,
        corsHeaders
      );
    }

    // Stripe webhook endpoint (uses its own auth via signature)
    if (path === '/webhooks/stripe' && method === 'POST') {
      const result = await handleStripeWebhook(request, env);
      return jsonResponse(result, 200, corsHeaders);
    }

    // All other routes require API authentication
    authenticate(request, env);

    // Parse JSON body for POST requests
    let body = null;
    if (method === 'POST') {
      try {
        body = await request.json();
      } catch {
        throw new AppError('Invalid JSON body', 400, 'INVALID_JSON');
      }
    }

    // ---- Email Routes ----
    if (path === '/api/email/send' && method === 'POST') {
      const result = await sendEmail(body, env);
      return jsonResponse(result, 200, corsHeaders);
    }

    // ---- Payment Routes ----
    if (path === '/api/payments/create-intent' && method === 'POST') {
      const result = await createPaymentIntent(body, env);
      return jsonResponse(result, 200, corsHeaders);
    }

    if (path.startsWith('/api/payments/intent/') && method === 'GET') {
      const paymentIntentId = path.split('/api/payments/intent/')[1];
      const result = await retrievePaymentIntent(paymentIntentId, env);
      return jsonResponse(result, 200, corsHeaders);
    }

    if (path === '/api/payments/refund' && method === 'POST') {
      const result = await createRefund(body, env);
      return jsonResponse(result, 200, corsHeaders);
    }

    // ---- Customer Routes ----
    if (path === '/api/customers/create' && method === 'POST') {
      const result = await createCustomer(body, env);
      return jsonResponse(result, 200, corsHeaders);
    }

    // ---- 404 ----
    throw new AppError(`Route not found: ${method} ${path}`, 404, 'NOT_FOUND');
  } catch (error) {
    return errorResponse(error, corsHeaders);
  }
}

// =====================
// Worker Export
// =====================

export default {
  async fetch(request, env, ctx) {
    return handleRequest(request, env, ctx);
  },
};